package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    void testGetHeaderCommentsReturnsCloneWhenNotNull() {
        // Create a new CSVFormat instance with headerComments set via withHeaderComments()
        CSVFormat format = CSVFormat.DEFAULT.withHeaderComments("comment1", "comment2");

        String[] originalComments = format.getHeaderComments();
        assertNotNull(originalComments);

        String[] result = format.getHeaderComments();
        assertNotNull(result);
        assertArrayEquals(originalComments, result);

        // Verify that returned array is a clone, not the same instance
        assertNotSame(originalComments, result);
    }

    @Test
    void testGetHeaderCommentsReturnsNullWhenNull() {
        // Create a new CSVFormat instance without headerComments set
        CSVFormat format = CSVFormat.DEFAULT.withHeaderComments((Object[]) null);

        String[] result = format.getHeaderComments();
        assertNull(result);
    }
}
